package com.cheehwatang.leetcode;

// Time Complexity  : O(m ^ n),
// where 'm' is the length of the words in 'words', and 'n' is the length of the string array 'words'.
// For each word in 'words' (of length n), other than the first at index 0, we check the differences between the letters
// for both strings (of length m) in the 'isDifferent()' function.
//
// Space Complexity : O(1),
// as we are only checking through each letters without using any HashMap.

public class OddStringDifference {

    // Approach:
    // Compare all the words in 'words' with the first word, words[0],
    // to evaluate find any or all is different to the first word.
    // If all is different, then we know the first word is the odd one out.
    // Otherwise, there will only be one word that is different to the first word.
    // Since we are only searching for the odd word, we can just count the matches and note the mismatched word.
    //
    // Credit: @ivey

    public String oddString(String[] words) {
        // 'matchWithFirstWord' to keep track on the number of word that matches the first word, words[0].
        int matchWithFirstWord = 0;
        // 'mismatchIndex' to keep track on the word that is different to the first word, words[0].
        int mismatchIndex = -1;

        for (int i = 1; i < words.length; i++) {
            if (isDifferent(words[0], words[i]))
                mismatchIndex = i;
            else
                matchWithFirstWord++;
        }
        // If the first word, words[0], is the odd one out,
        // then the 'mismatchIndex' will continue to update while 'matchWithFirstWord' remains at 0.
        // If there are multiple matches with the first word, words[0], then 'mismatchIndex' will only be updated once.
        return matchWithFirstWord > 0 ? words[mismatchIndex] : words[0];
    }

    // Function to check if the two strings have different "difference integers".
    // Return true if the two are different, and return false otherwise.
    private boolean isDifferent(String a, String b) {
        for (int i = 1; i < a.length(); i++) {
            if (a.charAt(i) - a.charAt(i - 1) != b.charAt(i) - b.charAt(i - 1))
                return true;
        }
        return false;
    }
}

package com.cheehwatang.leetcode;

import java.util.*;

// Time Complexity  : O(m ^ n),
// where 'm' is the length of the words in 'words', and 'n' is the length of the string array 'words'.
// For each word in 'words' (of length n), we check the differences between the letters, in the word of length m.
//
// Space Complexity : O(m ^ n),
// where 'm' is the length of the words in 'words', and 'n' is the length of the string array 'words'.
// Complexity 'm ^ n' as we create an int array of length 'm' for each word that we check in the string array 'words' of length 'n',
// to record the differences.
// There is actually an additional complexity of 'n', as we created a List<String> function to record the words.
// The HashMap<>() has only 2 key-value pairs in this problem, so it is negligible.

public class OddStringDifference_HashTable {

    // Approach:
    // As the words have their own difference integer array,
    // thus we can use a HashMap to record the occurrences of the difference integer array to see which is the odd one out.
    // Rather than recording the occurrences in count, we use a list to keep track of the words.
    // If the list only contains one word, then we know that word is the odd one out.

    public String oddString(String[] words) {
        // As we will be converting the difference integer array into its hash code, the key is the hash code of the array,
        // while the value is the list storing the string with that difference integer array hash code.
        // The reason for a hash code is that int[] as an array is a unique object even with the same elements in it.
        // Thus, we need to either convert it into its hash code (using Arrays.hashCode()) or String Arrays.toString())
        // for the int[] to be comparable.
        Map<Integer, List<String>> map = new HashMap<>();

        for (String word : words) {
            // Store the differences in an array.
            int[] difference = new int[word.length() - 1];
            for (int i = 0; i < word.length() - 1; i++) {
                difference[i] = word.charAt(i + 1) - word.charAt(i);
            }
            // Once we got the difference integer array, we convert it into a hash code, and
            // store together with the string in the HashMap.
            int hashCode = Arrays.hashCode(difference);
            // Note to create a new list for the strings if it is a new hash code.
            if (!map.containsKey(hashCode)) {
                map.put(hashCode, new ArrayList<>());
            }
            map.get(hashCode).add(word);
        }

        String oddString = "";
        // For this problem, there will only be two keys and one will only contain an element in the list.
        for (Integer key : map.keySet()) {
            if (map.get(key).size() == 1) {
                oddString = map.get(key).get(0);
            }
        }
        return oddString;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'text'.
// The String.split() method, String.chars() and filter(), and the string concatenation of the result string,
// all has linear time complexity.
//
// Space Complexity : O(n),
// where 'n' is the length of 'text'.
// The splitting of the 'text' to form a string array with approximately 'n' length.
// The string concatenation the form the result string has the same size as the input 'text'.

public class RearrangeSpacesBetweenWords {

    // Approach:
    // Count the spaces and words in the 'text'.
    // Then, we determine the count of spaces between words and trailing spaces.
    // Then create a new String using the determined counts.

    public String reorderSpaces(String text) {

        // String.trim() removes all the leading and trailing spaces.
        // String.split("\\s+") provide an array of words,
        // where words are determined as non-whitespace characters separated by spaces.
        String[] words = text.trim().split("\\s+");

        // Every element in 'words' array is a word.
        int wordCount = words.length;

        // .chars() returns a stream of char.
        // .filter(predicate) returns a stream of char that fulfills the predicate (in this case ch == ' ').
        // .count() returns the counts of elements in the stream.
        // Putting all together, it means counting the space char ' ' in the 'text'.
        int spaces = (int) text.chars().filter(ch -> ch == ' ').count();

        // Determine the maximum spacesBetweenWords. If only 1 word, spacesBetweenWords is 0.
        int spacesBetweenWords = wordCount > 1 ? spaces / (wordCount - 1) : 0;

        // Determine how many trailingSpaces remains.
        int trailingSpaces = spaces - spacesBetweenWords * (wordCount - 1);

        // First join all the words with the " " of spacesBetweenWords, then all the remaining trailingSpaces.
        return String.join(" ".repeat(spacesBetweenWords), words) + " ".repeat(trailingSpaces);
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n + m),
// where 'n' is the length of string 'date', and 'm' is the month.
// We split the string which has a linear time complexity to the length of the string.
// Then, we traverse the 'dayOfMonth' array for the number of months to get the day sum of the previous months.
//
// Space Complexity : O(n + 12),
// where 'n' is the length of string 'date'.
// The String.split() method results in creation of strings with total length of 'date'.
// The 'dayOfMonth' array has length of 12.

public class DayOfTheYear {

    // Approach:
    // Use an array of day in the months.
    // For each year, check for leap year and adjust the day in February accordingly.
    // Then, iterate from 0 to the previous month to sum the days in the previous month.
    // For that month, we sum the day of the month.

    public int dayOfYear(String date) {
        // Split the date String to the year, month and day.
        String[] str = date.split("-");

        // Array for the day of the month.
        int[] dayOfMonth = new int[]{31,28,31,30,31,30,31,31,30,31,30,31};

        // If the year is a leap year, increase the day in February (index 1) by 1.
        if (isLeapYear(Integer.parseInt(str[0]))) dayOfMonth[1] = 29;

        // Sum all the days in the previous months.
        int day = 0;
        for (int i = 0; i < Integer.parseInt(str[1]) - 1; i++) {
            day += dayOfMonth[i];
        }
        // Add the day to the total sum and return.
        return day + Integer.parseInt(str[2]);
    }

    // Method to check if the year is a leap year in the Gregorian calendar.
    private boolean isLeapYear(int year) {
        if (year % 400 == 0) return true;
        return year % 100 != 0 && year % 4 == 0;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(1),
// as it is only an arithmetic calculation.
//
// Space Complexity : O(1),
// as no additional space is used.

public class ValidBoomerang {

    // Approach:
    // The three points forms a boomerang when the points form different slopes.
    // The points are linear if they have the same slopes.
    // Thus,
    // Slope_AB = (yB - yA) / (xB - xA) == (p[1][1] - p[0][1]) / (p[1][0] - p[0][0])
    // Slope_BC = (yC - yB) / (xC - xB) == (p[2][1] - p[1][1]) / (p[2][0] - p[1][0])
    // Boomerang when Slope_AB != Slope_BC.
    // Rather than calculating the fractions, which could be problematic with floating points,
    // rearrange the equation by multiplying the equation by its denominators.
    // (Slope_AB != Slope_BC) == ((yB - yA) * (xC - xB) != (yC - yB) * (xB - xA)).
    //
    // Note: Another method is to calculate the area of the triangle to check if the area is > 0,
    //       with area = Math.abs((xA * (yB - yC)) + (xB * (yC - yA)) + (xC * (yA - yB)) / 2.

    public boolean isBoomerang(int[][] points) {
        // If the index of the array is confusing, we can use additional memory to
        // assign the coordinates to variables before calculating the slopes.
        // For Example: xA = points[0][0], xB = points[1][0], etc.
        return (points[1][1] - points[0][1]) * (points[2][0] - points[1][0])
                != (points[2][1] - points[1][1]) * (points[1][0] - points[0][0]);
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find the maximum depth of the tree.
//
// Space Complexity : O(m),
// where 'm' is the breadth of the tree.
// The maximum size of the 'queue' is the breadth of the tree.

public class MaximumDepthOfBinaryTree_BFS {

    // Approach:
    // Using breadth-first search to find the maximum depth of the tree.
    // Traverse the tree level by level, while keeping track of the level.
    // Once we have fully traversed the tree, the level is the maximum depth of the tree.

    public int maxDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Start the 'level' at 0, as we have yet to traverse the first level.
        int level = 0;

        // Breadth-first search is implemented using 'queue'.
        Queue<TreeNode> queue = new LinkedList<>();
        queue.offer(root);

        // If there are nodes in the 'queue', continue to traverse the tree level by level until all nodes are visited.
        while (!queue.isEmpty()) {
            // Each new level, we increase 'level' by 1.
            level++;

            // Remember to use a variable 'size' to keep track of the size of the queue,
            // as we want to traverse the tree one level at a time.
            for (int i = 0, size = queue.size(); i < size; i++) {
                TreeNode current = queue.poll();
                // If there are left or right child nodes, add them to the 'queue' for the next level.
                if (current.left != null) queue.offer(current.left);
                if (current.right != null) queue.offer(current.right);
            }
        }
        // Once all the nodes are visited, return the maximum depth of the tree.
        return level;
    }
}

package com.cheehwatang.leetcode;

import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find the maximum depth of the tree.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the 'nodeStack' and 'levelStack' is the depth of the tree.

public class MaximumDepthOfBinaryTree_DFS_Iterative {

    // Approach:
    // Using depth-first search to find and determine the depth of every root-to-leaf paths.
    // Then, compare and find the maximum depth whenever we arrived at a leaf node.
    // Here, the depth-first search is implemented iteratively.

    public int maxDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Both the depth and level of a tree describe the same thing.
        // Here, we use 'maxLevel' as a variable name to make it differ from the 'maxDepth()' method.
        int maxLevel = 0;

        // For iterative depth-first search,
        // we use 'nodeStack' for the nodes and 'levelStack' to for the level of the node.
        Stack<TreeNode> nodeStack = new Stack<>();
        Stack<Integer> levelStack = new Stack<>();

        // Each time pushing a node into the 'nodeStack', push the level of the node to the 'levelStack'.
        nodeStack.push(root);
        levelStack.push(1);

        while (!nodeStack.isEmpty()) {
            // Get the current node and level of the node.
            TreeNode currentNode = nodeStack.pop();
            int currentLevel = levelStack.pop();

            // Once we reach a leaf node, compare and update the 'maxLevel'.
            if (currentNode.left == null && currentNode.right == null) {
                maxLevel = Math.max(maxLevel, currentLevel);
                continue;
            }

            // If there are left or right child nodes,
            // add them to the 'nodeStack' as well as their level ('currentLevel' + 1) to 'levelStack'.
            if (currentNode.left != null) {
                nodeStack.push(currentNode.left);
                levelStack.push(currentLevel + 1);
            }
            if (currentNode.right != null) {
                nodeStack.push(currentNode.right);
                levelStack.push(currentLevel + 1);
            }
        }
        // Once all the nodes are visited, return the maximum depth of the tree.
        return maxLevel;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find the maximum depth of the tree.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the recursive call stack is the depth of the tree.

public class MaximumDepthOfBinaryTree_DFS_Recursive {

    // Approach:
    // Using depth-first search to find the depth of every node.
    // Then, compare and find the maximum depth.
    // Here, the depth-first search is implemented recursively.

    public int maxDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Traverse the left and right nodes.
        // The level of the 'root' is one level greater than the level of the left or the right node,
        // whichever is greater.
        return Math.max(maxDepth(root.left), maxDepth(root.right)) + 1;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(1),
// as no iteration is performed, only simple arithmetic calculations.
//
// Space Complexity : O(1),
// as only fixed variables are created.

public class RectangleArea {

    // Approach:
    // The area of a rectangle is the product of the sides on the x-axis and y-axis,
    // which is the difference of the x-coordinates and y-coordinates of the two diagonal corners.
    // For the overlap, we find the coordinates which is explained below, and get the product of its corners.
    // Using x-coordinates as example:
    // Rectangle A:         |           |          * Indicates the max for x1 and min for x2.
    //                     ax1*         ax2
    // Rectangle B:     |          |
    //                 bx1        bx2*
    // The overlap on the left is Math.max(ax1, bx1), while the right is Math.min(ax2, bx2).
    // The same applies for the y-coordinates.
    // If there are no overlap, then (Math.min(ax2, bx2) <= Math.max(ax1, bx1)) == (bx2 <= ax1).
    // Rectangle A:                     |           |       * Indicates the max for x1 and min for x2.
    //                                 ax1*         ax2
    // Rectangle B:     |          |
    //                 bx1        bx2*

    public int computeArea(int ax1, int ay1, int ax2, int ay2, int bx1, int by1, int bx2, int by2) {

        // It is helpful that ax2 > ax1, ay2 > ay1, bx2 > bx1, by2 > by1,
        // so there is no need to perform checks on the corner coordinates.
        // Calculate the area if rectangle A and B.
        int areaA = (ax2 - ax1) * (ay2 - ay1);
        int areaB = (bx2 - bx1) * (by2 - by1);

        // If there are any overlap, the top right corner coordinates of the overlap
        // will be the minimum of the top right of both A and B.
        int top = Math.min(ay2, by2);
        int right = Math.min(ax2, bx2);

        // Likewise for the bottom left corner is the maximum of the bottom left of both A and B.
        int bottom = Math.max(ay1, by1);
        int left = Math.max(ax1, bx1);

        // If the top right corner and bottom left corner is not in the correct position,
        // then rectangle A and B do not overlap.
        // There are overlap only if top > bottom and right > left.
        int overlap = 0;
        if (top > bottom && right > left)
            overlap = (top - bottom) * (right - left);

        // The total area covered is rectangle A and rectangle B, except for the double count of overlap, if any.
        return areaA + areaB - overlap;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the longest bits of the number 'a' or 'b'.
// The worst-case is when the while-loop occurs for numbers such as 11111 + 1,
// which loops for 5 times until the result 100000.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class SumOfTwoIntegers {

    // Approach:
    // Using bit manipulation, with the bitwise AND '&' to get the carries (1 + 1 = 0 carries 1),
    // and with bitwise XOR '^' to get the 1s that remains in that position.
    // For example, 1 + 1 = 10, with 1 & 1 = 1, and 1 ^ 1 = 0.
    // We then use bitwise left shift for the carries, 1 << 1 = 10.
    // Repeat the process with 10 & 0 = 0, 10 ^ 0 = 10.
    // With that, we have found to sum of 1 + 1 to be 2 (or binary 10).

    public int getSum(int a, int b) {
        // If either is zero, return the non-zero number.
        if (a == 0) return b;
        if (b == 0) return a;

        // While there are still carries remain.
        // For this, we use 'b' to hold the carries.
        while (b != 0) {
            int carries = a & b;
            a = a ^ b;
            // Left shift the carries by one bit.
            b = carries << 1;
        }
        return a;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;
import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse the nodes from right to left to flatten the tree to a linked list.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree.
// For this approach, we use a List to keep track of the preorder arrangement of the binary tree.
// The list has the size of 'n', with all the nodes in it.

public class FlattenBinaryTreeToLinkedList_Iterative {

    // Approach:
    // Perform the usual preorder traversal, but use a list to keep track of the ordering of nodes.
    // Once we have the preorder arrangements of the nodes,
    // set the left child node to null and right child node to the next node in order.

    public void flatten(TreeNode root) {
        if (root == null) return;

        // Using the iterative implements of the preorder traversal, and use a List to record the preorder arrangement.
        List<TreeNode> preorderList = new LinkedList<>();
        Stack<TreeNode> stack = new Stack<>();
        stack.push(root);
        while (!stack.isEmpty()) {
            TreeNode current = stack.pop();
            // Preorder traversal first visits the node, then the left node, then the right node.
            // Since we are using stack, we push the right node first, then left,
            // as we are visiting the left node before the right node, with stack being FILO (First-In Last-Out).
            preorderList.add(current);
            if (current.right != null) stack.push(current.right);
            if (current.left != null) stack.push(current.left);
        }

        // Once we have the list of nodes in the preorder arrangement,
        // we traverse the list to set the left child node to null, and the right child node to the next node.
        TreeNode current = root;
        current.left = null;
        for (int i = 1; i < preorderList.size(); i++) {
            current.right = preorderList.get(i);
            current = current.right;
            current.left = null;
        }
        current.right = null;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse the nodes from right to left to flatten the tree to a linked list.
//
// Space Complexity : O(1),
// as we are only changing the left and right pointers in each node to flatten the tree.

public class FlattenBinaryTreeToLinkedList_Recursive {

    // As we are using flatten() as recursive method, we need to store the 'previous' node outside of the method.
    TreeNode previous = null;

    public void flatten(TreeNode root) {
        if (root == null) return;

        // As we are flattening the binary tree in the preorder arrangement, we flatten the right child node first.
        flatten(root.right);
        flatten(root.left);
        // As we flatten, we set the left child node to null and the right to the previous node checked.
        // This ensures we flatten from the rightmost leaf node to the leftmost leaf node.
        root.left = null;
        root.right = previous;
        previous = root;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(logn),
// where 'n' is the length of 'citations'.
// We perform the binary search once, with O(logn) time complexity.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input size.

public class HIndexII {

    // Approach:
    // The problem is asking us to find the maximum paper count with citation values greater than the paper count.
    // As such, we need to find the intersection between the paper count and the citations,
    // checking each citation in ascending order while decreasing the paper count (n - i),
    // the H-Index is when the paper count is less than or equal to citation,
    // with the remaining citations to be at least the number of paper.
    //
    // We can optimize this with binary search,
    // checking lower citation number if we found an index fulfilling the H-Index condition,
    // or checking the higher citation number if the index fails the H-Index condition.
    // Continue to binary search until we find the H-Index.

    public int hIndex(int[] citations) {
        int n = citations.length;
        int start = 0;
        int end = n;

        int result = 0;
        // While the 'start' and 'end' pointers not meet,
        while (start < end) {
            // Get the midpoint.
            // Note: Performing "(end + start) / 2" does not result in overflow in this case,
            //       as the constraint is "1 <= n <= 10e5".
            // However, the operations below is recommended as best practice to prevent overflow.
            int mid = (end - start) / 2 + start;
            // The paper count with greater or equal citation is "n - mid".
            int paper = n - mid;

            // If the condition is met, record the result,
            // and check for the lower citation number (higher paper number).
            if (paper <= citations[mid]) {
                result = paper;
                end = mid;
            } else {
                // Else, check the higher citation number (lower paper number).
                start = mid + 1;
            }
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse the binary tree in-order, comparing each value with the previous value to check if the nodes
// are arranged in-order.
//
// Space Complexity : O(m),
// where 'm' is the depth of the binary tree.
// The size of the stack used in the in-order traversal has a maximum size equivalent to the depth of the tree.

public class ValidateBinarySearchTree_DFS_Iterative {

    // Approach:
    // Perform in-order traversal, comparing the value of the nodes to the previous node.
    // If the current node value is lesser or equal to the previous node value, then it is not a valid
    // binary search tree.
    // For in-order traversal, we use stack to record the nodes to be visited, visiting the nodes in the order of:
    // 1. Left node (until we hit null, while storing the nodes in the stack).
    // 2. Visit the root node, and get the difference with the previous node.
    // 3. Right node (if any, then restart step 1 and step 2).

    public boolean isValidBST(TreeNode root) {
        // For the first node, we need the 'previous' value to be a default false value.
        // As the range of the node values are from Integer.MIN_VALUE to Integer.MAX_VALUE,
        // we use one lower in the long type to indicate default false value.
        long previous = (long) Integer.MIN_VALUE - 1;

        // Iterative depth-first search is performed using a stack to store the nodes.
        Stack<TreeNode> stack = new Stack<>();

        // We use a pointer to keep track of the current node.
        TreeNode current = root;

        // At any point, if the pointer is null and the stack is empty, we have fully traversed the tree.
        while (current != null || !stack.isEmpty()) {
            // For any node, completely traverse the left branch.
            while (current != null) {
                stack.push(current);
                current = current.left;
            }
            // Get the top node in the stack.
            current = stack.pop();

            // Compare the current node value with the previous value.
            // If the current node value is lesser or equal to the previous node value, then it is not a valid
            // binary search tree.
            if (previous != (long) Integer.MIN_VALUE - 1 && current.val <= previous) return false;
            previous = current.val;

            // Visit the right node (if any).
            // Note that if the right node is null, the pointer is null, which will continue to pop the stack.
            // If ever the right node is not null, then we fully traverse its left branch.
            current = current.right;
        }
        // Return the minimum difference between any two nodes once all the nodes are traversed.
        return true;
    }
}

