// Time Complexity  : O(n),
// where 'n' is the length of string 's'.
// We traverse the string 's' once to check for the bad pair.
//
// Space Complexity : O(n),
// where 'n' is the length of string 's'.
// We use StringBuilder which scales linearly with the length of string 's',
// and the final result string also scales linearly with the length of string 's'.

public class MakeTheStringGreat_Stack {

    // Approach:
    // Using stack to check for the bad character pairs is suitable here,
    // because some bad character pairs can be found after other character pairs are removed, for example "abcCBA" -> "".
    //
    // To check if the adjacent characters are the same letter with different case,
    // we can check if the two characters are of lower and upper case, if they are different by 32,
    // This is because the ASCII value for 'a' is 97, and 'A' is 65, with 97 - 65 == 32.

    public String makeGood(String s) {
        int n = s.length();
        // Rather than using Stack<> and StringBuilder together, we can just use a StringBuilder for the function of stack,
        // by checking the last / rightmost character in the StringBuilder.
        // Since the StringBuilder is backed by an array with default initial capacity of 16,
        // we can set the initial capacity to the maximum length possible to prevent inefficiency in resizing when
        // s.length() > 16.
        StringBuilder stringBuilder = new StringBuilder(n);

        for (int i = 0; i < n; i++) {
            char current = s.charAt(i);
            // Check if the 'stringBuilder' is empty, as it results in IndexOutOfBound error if not checked.
            // Using Math.abs(), we can check if the two characters are of different cases but same letter,
            // regardless which is lowercase or uppercase.
            // If found the bad pair, remove the rightmost character in the 'stringBuilder', like a stack.
            if (stringBuilder.length() > 0 && Math.abs(current - stringBuilder.charAt(stringBuilder.length() - 1)) == 32)
                stringBuilder.deleteCharAt(stringBuilder.length() - 1);

            // If not, then add the character to the 'stringBuilder'.
            else stringBuilder.append(current);
        }
        return stringBuilder.toString();
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// We traverse 'nums' twice, firstly to count, and secondly to replace the sorted numbers in 'nums',
// giving a time complexity of O(n).
// However, we used a sort function, which implements the Double Pivot Quicksort,
// which has an average time complexity of O(n logn).
// This would happen if all the values in 'nums' are unique, resulting in sorting 'n' number of integers.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// We use HashMap to count the frequency of the numbers.
// The worst-case is when all the integers in 'nums' are unique, resulted in the size of 'n' for the HashMap.
// As we reused the 'nums' array for the final result, that did not contribute to additional space complexity.

public class SortArrayByIncreasingFrequency {

    // Approach:
    // First, we use a HashMap to count the frequency of the integers in 'nums'.
    // With that, we need to sort the frequencies in ascending order,
    // while sorting the integers with the same frequency in descending order.
    // As we cannot sort a HashMap, we convert the HashMap into an array to sort.
    // According to the sorted array, modify the 'nums' array with the new sorted sequence.

    public int[] frequencySort(int[] nums) {

        // Use a HashMap to count the frequency of the integer, with the key -> integer, and value -> frequency.
        Map<Integer, Integer> integerFrequency = new HashMap<>();
        for (int number : nums) {
            integerFrequency.put(number, integerFrequency.getOrDefault(number, 0) + 1);
        }

        // Convert the HashMap into an array,
        // with frequencyList[i][0] -> integer, and frequencyList[i][1] -> frequency.
        int[][] frequencyList = new int[integerFrequency.size()][2];
        int index = 0;
        for (Integer integer : integerFrequency.keySet()) {
            frequencyList[index++] = new int[]{integer, integerFrequency.get(integer)};
        }

        // Sort the array with the frequencies in ascending order,
        // while sorting the integers with the same frequency in descending order.
        Arrays.sort(frequencyList, (a, b) -> a[1] == b[1] ? b[0] - a[0] : a[1] - b[1]);

        // Replace the values in 'nums' with the new sorted sequence.
        int indexInNums = 0;
        for (int[] frequency : frequencyList) {
            for (int i = 0; i < frequency[1]; i++) {
                nums[indexInNums++] = frequency[0];
            }
        }

        // Return the sorted array.
        return nums;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 's'.
// We traverse the string 's' once to count the vowels in the two halves.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input string.

public class DetermineIfStringHalvesAreAlike {

    // Approach:
    // We traverse the two halves to count the number of vowels.
    // Return true if the vowel counts are equal.

    public boolean halvesAreAlike(String s) {
        int n = s.length();

        int count1 = 0;
        int count2 = 0;
        // We only need to traverse half of the String 's',
        // since we can get the character of the second half with "i + n / 2".
        for (int i = 0; i < n / 2; i++) {
            // Add to the count if we found a vowel for each respective halves.
            if (isVowel(s.charAt(i))) count1++;
            if (isVowel(s.charAt(i + n / 2))) count2++;
        }
        // If the counts for both halves are equal, return true.
        return count1 == count2;
    }

    // Helper method to determine if the character is vowel.
    // This helps with readability.
    private boolean isVowel(char character) {
        final String VOWELS = "aeiouAEIOU";
        // If the index is >= 0, then 'character' is a vowel.
        // If the index is -1, then 'character' is not a vowel.
        return VOWELS.indexOf(character) != -1;
    }
}

package com.cheehwatang.leetcode;

/**
 * Your MyLinkedList object will be instantiated and called as such:
 * MyLinkedList obj = new MyLinkedList();
 * int param_1 = obj.get(index);
 * obj.addAtHead(val);
 * obj.addAtTail(val);
 * obj.addAtIndex(index,val);
 * obj.deleteAtIndex(index);
 */

public class DoublyLinkedList {

    // For Doubly Linked List, all the nodes are connected bi-directionally that ends in null in both ends.
    // However, the 'head' and 'tail' pointer still points to the head and tail of the linked list respectively.
    // For example null <- A <-> B <-> C <-> D -> null, with A being the head and D being the tail.
    // Thus, all the nodes has the 'val' field, the 'next' variable which points to the next node,
    // and the 'prev' variable which points to the previous node.
    private class Node {
        private int val;
        private Node next;
        private Node prev;

        // Constructor of the Node.
        public Node(int val) {
            this.val = val;
            this.next = null;
            this.prev = null;
        }
    }

    // For Doubly Linked List, we use a 'head' node and a 'tail' node to represent the whole linked list,
    // so we can traverse the linked list from either the 'head' or the 'tail'.
    // Here, we use a 'size' variable to keep track of the size of the Linked List for fast operations
    // for adding and deleting nodes.
    private Node head;
    private Node tail;
    private int size;

    // Constructor of the Doubly Linked List, with a null 'head', null 'tail' and 'size' of 0.
    public DoublyLinkedList() {
        this.head = null;
        this.tail = null;
        this.size = 0;
    }

    // Function to get the value of the node at position 'index'.
    public int get(int index) {
        // If the 'index' is out of bound, return -1.
        if (index > size - 1 || index < 0) return -1;

        // Using for-loop to traverse the linked list until the node at position 'index'.
        // We can also use a while-loop to traverse.
        Node current = head;
        for (; index > 0; index--)
            current = current.next;

        // Return the value of the node.
        return current.val;
    }

    // A private function for a simple operation to add a node to an empty list.
    // As all three functions, addAtHead(val), addAtTail(val) and addAtIndex(index, val)
    // have the possibilities of adding a node to an empty linked list.
    // We extract the function out, rather than duplicating the code in all three functions.
    private void addInEmptyList(int val) {
        // Set both the 'head' and 'tail' as the new node, as both are currently null.
        head = new Node(val);
        tail = head;

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to add a new node of 'val' value to the head of the linked list.
    public void addAtHead(int val) {
        // If we have an empty list, then we use the addInEmptyList(val).
        if (size == 0) {
            addInEmptyList(val);
            return;
        }

        // For doubly linked list, we need to remap both the 'next' and 'prev' pointers.
        Node newNode = new Node(val);
        newNode.next = head;
        head.prev = newNode;
        head = newNode;

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to add a new node of 'val' value to the tail of the linked list.
    public void addAtTail(int val) {
        // If we have an empty list, then we use the addInEmptyList(val).
        if (size == 0) {
            addInEmptyList(val);
            return;
        }

        // Adding a new node in the 'tail' is similar to adding it to the head of the linked list.
        Node newNode = new Node(val);
        newNode.prev = tail;
        tail.next = newNode;
        tail = newNode;

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to add a new node of 'val' value to the position 'index' in the linked list.
    public void addAtIndex(int index, int val) {
        // If the 'index' is out of bound, return -1.
        if (index > size || index < 0) return;

        // If we have an empty list, then we use the addInEmptyList(val).
        if (size == 0) {
            addInEmptyList(val);
            return;
        }

        // If index is 0, we add at the head.
        if (index == 0) {
            addAtHead(val);
        }
        // If index is size, we add at the tail.
        else if (index == size) {
            addAtTail(val);
        }
        // If somewhere in between,
        else {
            // traverse the linked list until the parent position of the 'index' to add.
            Node parent = head;
            for (; index > 1; index--) {
                parent = parent.next;
            }
            // Change the pointers accordingly when adding the new node.
            // For Example, Linked List == A <-> B -> null, index to add is 1, value is C.
            Node newNode = new Node(val);
            // So parent == A, parent.next == B, newNode == C,
            // make C <- B -> null.
            parent.next.prev = newNode;
            // make C <-> B -> null.
            newNode.next = parent.next;
            // make A <- C <-> B -> null.
            newNode.prev = parent;
            // make A <-> C <-> B -> null.
            parent.next = newNode;

            // After adding the node, increase the size by 1.
            size++;
        }
    }

    // Function to delete the node at position 'index' in the linked list.
    public void deleteAtIndex(int index) {
        // If the 'index' is out of bound, return -1.
        if (index > size - 1 || index < 0) return;

        // For the edge case of only one node in the linked list, set both the 'head' and 'tail' pointer as null.
        if (size == 1) {
            head = null;
            tail = null;
            size--;
            return;
        }

        // If we are deleting the node at the head of the list,
        // set the 'head' to the next node, and remember to set the 'prev' of the new head as null.
        if (index == 0) {
            head = head.next;
            head.prev = null;
        }
        // If we are deleting the node at the tail of the list,
        // set the 'tail' to the previous node, and remember to set the 'next' of the new tail as null.
        else if (index == size - 1) {
            tail = tail.prev;
            tail.next = null;
        }
        // For any other positions,
        else {
            // traverse the linked list until the node at the 'index' to delete.
            Node current = head;
            for (; index > 0; index--) {
                current = current.next;
            }

            // Point the 'prev' node and 'next' node to each other.
            current.prev.next = current.next;
            current.next.prev = current.prev;
        }

        // After deleting the node, decrease the size by 1.
        size--;
    }
}

package com.cheehwatang.leetcode;

/**
 * Your MyLinkedList object will be instantiated and called as such:
 * MyLinkedList obj = new MyLinkedList();
 * int param_1 = obj.get(index);
 * obj.addAtHead(val);
 * obj.addAtTail(val);
 * obj.addAtIndex(index,val);
 * obj.deleteAtIndex(index);
 */

public class SinglyLinkedList {

    // For Singly Linked List, all the nodes are connected in one direction that ends in null.
    // For example A -> B -> C -> D -> null.
    // Thus, all the nodes has the 'val' field and the 'next' variable which points to the next node.
    private class Node {
        private int val;
        private Node next;

        // Constructor of the Node.
        public Node(int val) {
            this.val = val;
            this.next = null;
        }
    }

    // For Singly Linked List, we use a 'head' node to represent the whole linked list,
    // as we can get to all the nodes using the 'head' node.
    // Here, we use a 'size' variable to keep track of the size of the Linked List for fast operations
    // for adding and deleting nodes.
    private Node head;
    private int size;

    // Constructor of the Singly Linked List, with a null 'head' and 'size' of 0.
    public SinglyLinkedList() {
        this.head = null;
        this.size = 0;
    }

    // Function to get the value of the node at position 'index'.
    public int get(int index) {
        // If the 'index' is out of bound, return -1.
        if (index > size - 1 || index < 0) return -1;

        // Using for-loop to traverse the linked list until the node at position 'index'.
        // We can also use a while-loop to traverse.
        Node current = head;
        for (; index > 0; index--)
            current = current.next;

        // Return the value of the node.
        return current.val;
    }

    // Function to add a new node of 'val' value to the head of the linked list.
    public void addAtHead(int val) {
        // Simply create the new node, point the 'next' to the 'head', and set the new node as the 'head'.
        Node newNode = new Node(val);
        newNode.next = head;
        head = newNode;

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to add a new node of 'val' value to the tail of the linked list.
    public void addAtTail(int val) {
        // If there are no nodes in the linked list, we can use the addAtHead(val) function.
        if (size == 0) {
            addAtHead(val);
            return;
        }

        // Else, we traverse the linked list until the very last node and point the 'next' to the new node.
        Node current = head;
        while (current.next != null)
            current = current.next;
        current.next = new Node(val);

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to add a new node of 'val' value to the position 'index' in the linked list.
    public void addAtIndex(int index, int val) {
        // If the 'index' is out of bound, exit the function.
        if (index > size || index < 0) return;

        // If the index is 0, meaning that we add the node to the head of the linked list
        // using the addAtHead(val) function.
        // As it is an edge case, we handle it differently from the other nodes.
        if (index == 0) {
            addAtHead(val);
            return;
        }

        // Traverse the linked list, noting on the 'parent' of the position to add the new node.
        // Note that this is a singly linked list,
        // so we can only get the parent of a node by traversing the linked list from the head.
        Node parent = head;
        for (; index > 1; index--) {
            parent = parent.next;
        }
        // Change the pointers accordingly when adding the new node.
        // For Example, Linked List == A -> B -> null, index to add is 1, value is C.
        Node newNode = new Node(val);
        // So parent == A, parent.next == B, newNode == C,
        // making C -> B -> null, the linked list remains as A -> B -> null.
        newNode.next = parent.next;
        // Then, parent -> newNode, making A -> C -> B -> null.
        parent.next = newNode;

        // After adding the node, increase the size by 1.
        size++;
    }

    // Function to delete the node at position 'index' in the linked list.
    public void deleteAtIndex(int index) {
        // If the 'index' is out of bound, exit the function.
        if (index > size - 1 || index < 0) return;

        // If the index is 0, meaning that we remove the node to the head of the linked list.
        // As it is an edge case, we handle it differently from the other nodes.
        if (index == 0) {
            head = head.next;
            size--;
            return;
        }

        // Traverse the linked list, noting on the 'parent' of the position to add the new node.
        // Note that this is a singly linked list,
        // so we can only get the parent of a node by traversing the linked list from the head.
        Node parent = head;
        for (; index > 1; index--) {
            parent = parent.next;
        }

        // To delete the node, simply set the 'next' node pointer to skip the node to delete.
        // Note that the node "deleted" still remains in memory, as well as its 'next' pointer,
        // but it no longer remains in the linked list.
        parent.next = parent.next.next;

        // After deleting the node, decrease the size by 1.
        size--;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(nlogn),
// where 'n' is the number of stones, and nlogn due to the sorting algorithm.
//
// Space Complexity : O(n),
// where 'n' is the number of stones, because of the new int[] created before sorting the stones.

public class MovingStonesUntilConsecutive {

    // Approach:
    // For we sort the stones to get the leftmost and rightmost position.
    // There are mainly three cases for the minimum moves:
    // 1. Stones are already in position, no moves possible (e.g. a = 1, b = 2, c = 3).
    // 2. Only one move is needed:
    //    - When two stones are already adjacent, move the remaining stone next to the other stones.
    //      (e.g. a = 1, b = 2, c = 5)
    //    - When two stones are 1 space apart, move the remaining stone between the two stones.
    //      (e.g. a = 1, b = 3, c = 6)
    // 3. Two moves needed, when all three stones are far apart from one another.
    //
    // For the maximum moves, basically just move the stone one position at a time, which is the spaces among the stones.

    public int[] numMovesStones(int a, int b, int c) {
        int[] stones = new int[]{a, b, c};
        Arrays.sort(stones);
        // Case 1.
        if (stones[1] - stones[0] == 1 && stones[2] - stones[1] == 1) {
            return new int[]{0, 0};
        }
        // For Case 2 and Case 3, the maximum moves for the spaces among the stones are the leftmost - rightmost - 2,
        // -1 for the conversion from index to spaces (index 1 and 3 has only 1 space, but index difference is 2).
        // -1 for the stone in the middle that cannot be occupied by the other two stones.
        //
        // Case 2, if either two stones are adjacent or with 1 space in between.
        if (stones[1] - stones[0] <= 2 || stones[2] - stones[1] <= 2) {
            return new int[]{1, stones[2] - stones[0] - 2};
        }
        // Case 3.
        return new int[]{2, stones[2] - stones[0] - 2};
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'coordinates'.
// We traverse the 'coordinates' array to check if the coordinate with reference point has the same slope.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the input size.

public class CheckIfItIsAStraightLine {

    // Approach:
    // For the coordinates to be on the same straight line,
    // all the coordinates need to have the slope to a reference coordinate.
    // A slope, between coordinate A and B, is "(xB - xA) / (yB - yA)".
    // With the third coordinate C, the slope reference to coordinate A is "(xC - xA) / (yC - yA)".
    // Thus, the 3 points form a straight line if (xB - xA) / (yB - yA) == (xC - xA) / (yC - yA).
    // As floats or doubles can be unpredictable, we would rearrange the equation as such:
    // "(xB - xA) * (yC - yA) == (yB - yA) * (xC - xA)"
    // Using point A as the reference point, and slope A and B to be the reference slope,
    // we simplify the equation to "dx * (yC - yA) == dy * (xC - xA)".
    // We iterate through 'coordinates' to compare the slopes, return false if any slope is different.
    // If all points has the same slope, then return true.

    public boolean checkStraightLine(int[][] coordinates) {
        // Assign coordinates to variables for readability.
        int x0 = coordinates[0][0], y0 = coordinates[0][1], x1 = coordinates[1][0], y1 = coordinates[1][1];
        // Using the first and second point as reference slope.
        int dx = x1 - x0, dy = y1 - y0;
        for (int[] coordinate : coordinates) {
            int x = coordinate[0], y = coordinate[1];
            // Using coordinates[0] as reference point.
            // If the slope is different, return false.
            if (dy * (x - x0) != dx * (y - y0)) return false;
        }
        // If all coordinates have the same slope, return true.
        return true;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n^2),
// where 'n' is the length of 'nums'.
// For each position, we check every possible jumping positions to get the minimum steps.
// As such, the worst-case is when every position can reach every other positions after it.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// We used an array to memoize the minimum jumps to get from index 0 to index 'n - 1'.

public class JumpGameII_DynamicProgramming_Memoization {

    // Approach:
    // Using the dynamic programming and the memoization technique,
    // we can use a memo to record the minimum number of jump from any positions to arrive at index 'n - 1'.
    // With the recursive method call starting at index 0, we will increase the count by 1 for each jump,
    // and the breaking condition for the recursive calls is when we arrive at the last position 'n - 1'.
    // As we return zero jump from the last position, the recursive calls will increase the jump count by 1
    // for each return of the recursive call stack, at the same time getting the minimum count for each return.
    // We all the recursive calls collapse back to the first method call,
    // memo[0] will have the minimum jump count needed to get from index 0 to index 'n - 1'.

    public int jump(int[] nums) {
        // Create the integer array to memoize the minimum jump count from any position to position 'n - 1'.
        int[] memo = new int[nums.length];
        // As the constraint stated that the size of 'nums' is <= 10^4, we use 10001 for indicate position
        // that is unable to get to index 'n - 1'.
        // Note: Use of Integer.MAX_VALUE may result in integer overflow to Integer.MIN_VALUE,
        // thus affecting the Math.min check to get the minimum jump count for that position.
        Arrays.fill(memo, 10001);

        // Call the recursive method to return the minimum jumps needed to get from index 0 to index 'n - 1'.
        return jump(nums, 0, memo);
    }

    // Recursive method.
    private int jump(int[] nums, int position, int[] memo) {
        // Breaking condition, return 0 when the position is at or after the last position 'n - 1'.
        if (position >= nums.length - 1) return 0;
        // Return the jump count if it is already recorded in the memo.
        if (memo[position] != 10001) return memo[position];

        // For each possible jump position, increase the jump count by 1 and
        // call the recursive method for the next position.
        for (int i = 1; i <= nums[position]; i++) {
            memo[position] = Math.min(memo[position], 1 + jump(nums, position + i, memo));
        }

        // Return the minimum jump count from the current position to the last position 'n - 1'.
        return memo[position];
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n^2),
// where 'n' is the length of 'nums'.
// For each position, we check every possible jumping positions to get the minimum steps.
// As such, the worst-case is when every position can reach every other positions after it.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// We used an array to tabulate the minimum jumps to get from index 0 to index 'n - 1'.

public class JumpGameII_DynamicProgramming_Tabulation {

    // Approach:
    // Using the dynamic programming and the tabulation technique,
    // we can use a table to propagate the minimum number of jump that we need to take, starting from position 0.
    // With the index 0 in the array being zero jumps,
    // all the positions that we can jump to will have minimum of 1 jump.
    // Update the table accordingly with the least number of jumps required to arrive.

    public int jump(int[] nums) {
        int n = nums.length;

        // Set the table array with all the values being Integer.MAX_VALUE,
        // as we are getting the minimum number of jumps for each check.
        int[] table = new int[n];
        Arrays.fill(table, Integer.MAX_VALUE);
        // Set the first position as zero jumps, as we have not made any jumps.
        table[0] = 0;

        // Propagate the number of jumps to arrive at each position up, start with position 0 of zero jumps.
        for (int i = 0; i < n; i++) {
            // For each position, we update the minimum number of jumps to jump to all the reachable positions.
            for (int j = i; j < n && j <= i + nums[i]; j++)
                table[j] = Math.min(table[j], table[i] + 1);
        }
        // The last position of the table has the minimum number of jumps required to jump from index 0.
        return table[n - 1];
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the array 'nums' once to find the minimum steps to reach position 'n - 1'.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the size of 'nums'.

public class JumpGameII_Greedy {

    // Approach:
    // For any position, where the range of the current jump is from 'start' to 'end',
    // the farthest point to make the jump from the current position is 'end'.
    // Then, we check all the point from 'start' to 'end' to determine the next farthest point 'farthest' to jump.
    // We then make the jump and check the next farthest points from 'end' to 'farthest',
    // each time recording the number of times we jumped.
    // We continue the process until we check all the positions in 'nums'.

    public int jump(int[] nums) {
        // 'currentEnd' keeps track of the last position to make the jump.
        // 'currentFarthest' keeps track of the farthest position that we can jump to.
        int result = 0, currentEnd = 0, currentFarthest = 0;

        // Traverse the whole array, except for the last position in 'nums' as that is the destination.
        for (int i = 0; i < nums.length - 1; i++) {
            // Record the furthest position we can jump to.
            currentFarthest = Math.max(currentFarthest, i + nums[i]);
            // If we have arrived at the last position to make the jump,
            if (i == currentEnd) {
                // we jump, increasing the count by 1,
                result++;
                // and we set the next last position to jump as 'currentFarthest'.
                currentEnd = currentFarthest;
            }
        }
        return result;
    }
}
